document.addEventListener("DOMContentLoaded",()=>{const t=document.getElementById("edit-btn");if(!t)return;const e=document.querySelector('meta[name="csrf-token"]')?.content||"";function updateProgress(t,e,o){const n=e>0?Math.round(t/e*100):0,s=document.getElementById("enhmr-progress-bar"),r=document.getElementById("enhmr-progress-label"),i=document.getElementById("enhmr-progress-count");s&&(s.style.width=`${n}%`,s.textContent=`${n}%`,s.setAttribute("aria-valuenow",n)),r&&o&&(r.textContent=o),i&&(i.textContent=t.toLocaleString("el-GR"))}async function sendChunk(t){const o=await fetch("/api/enhmeroshKlimakion",{method:"POST",headers:{"Content-Type":"application/json","CSRF-Token":e},credentials:"include",skipLoader:!0,body:JSON.stringify(t)});if(!o.ok)throw new Error(`HTTP error ${o.status}`);return(o.headers.get("content-type")||"").includes("application/json")?await o.json():{success:!0}}t.addEventListener("click",async function handleEditClick(t){t.preventDefault(),t.stopPropagation();const e=window.dataForUpdate??[];if(!Array.isArray(e)||0===e.length)return void await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"info",title:"Δεν υπάρχουν δεδομένα",text:"Δεν βρέθηκαν εγγραφές προς ενημέρωση.",showConfirmButton:!0,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-info custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}});const o=e.length,n=[];for(let t=0;t<e.length;t+=1e3)n.push(e.slice(t,t+1e3));!function openProgressSwal(t){Swal.fire({backdrop:!1,allowOutsideClick:!1,title:"Αποθήκευση κλιμακίων...",html:`\n                <div id="enhmr-progress-label" class="mb-2 fsvw-1_0">\n                    Αρχικοποίηση...\n                </div>\n                <div class="mb-2">\n                    Επεξεργασία εγγραφών:\n                    <b id="enhmr-progress-count">0</b> / <b>${t.toLocaleString("el-GR")}</b>\n                </div>\n                <div class="progress" style="height: 22px; border-radius: 8px;">\n                    <div\n                        id="enhmr-progress-bar"\n                        class="progress-bar progress-bar-striped progress-bar-animated bg-success"\n                        role="progressbar"\n                        style="width: 0%;"\n                        aria-valuenow="0"\n                        aria-valuemin="0"\n                        aria-valuemax="100">\n                        0%\n                    </div>\n                </div>\n            `,showConfirmButton:!1,didOpen:()=>Swal.hideLoading()})}(o);try{let t=0,e=0,s=0;for(let r=0;r<n.length;r+=4){const i=n.slice(r,r+4);updateProgress(s,o,`Αποστολή εγγραφών ${(s+1).toLocaleString("el-GR")} – ${Math.min(s+i.reduce((t,e)=>t+e.length,0),o).toLocaleString("el-GR")}...`),(await Promise.all(i.map(t=>sendChunk(t)))).forEach((o,n)=>{s+=i[n].length,t+=o?.stats?.modified??0,e+=o?.stats?.upserted??0}),updateProgress(s,o,s>=o?"Ολοκλήρωση...":`Αποθηκεύτηκαν ${s.toLocaleString("el-GR")} από ${o.toLocaleString("el-GR")} εγγραφές...`)}await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"success",title:"Επιτυχής ενημέρωση!",html:`\n                    Σύνολο εγγραφών: <b>${o.toLocaleString("el-GR")}</b><br>\n                    Ενημερώθηκαν: <b>${t.toLocaleString("el-GR")}</b><br>\n                    Νέες εγγραφές: <b>${e.toLocaleString("el-GR")}</b>\n                `,showConfirmButton:!0,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-success custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}}).then(()=>{window.location.href="/symbaseis/ypologismoiKlimakion"})}catch(t){await Swal.fire({backdrop:!1,allowOutsideClick:!1,icon:"error",title:"Αποτυχία ενημέρωσης κλιμακίων",text:String(t?.message||t),showConfirmButton:!0,confirmButtonText:"Κλείσιμο",customClass:{confirmButton:"class-error custom-confirm-button custom-swal-button",title:"custom-title",popup:"custom-swal-popup"}})}})});